        group_value = metadata.get(group_by_field)
        if group_value is None:
            group_value = 'unknown'
        groups[group_value].append(result)

    # Define default aggregation functions
    if aggregation_funcs is None:
        aggregation_funcs = {
            'count': lambda x: len(x),
            'avg_score': lambda x: sum(r.score for r in x) / len(x) if x else 0,
            'max_score': lambda x: max(r.score for r in x) if x else 0,
            'min_score': lambda x: min(r.score for r in x) if x else 0
        }

    # Calculate statistics for each group
    result_dict = {}
    for group_value, results in groups.items():
        group_stats = {}

        # Apply all aggregation functions
        for field_name, func in aggregation_funcs.items():
            try:
                if field_name == 'count':
                    group_stats[field_name] = func(results)
                elif field_name.startswith('avg_') or field_name.startswith('max_') or field_name.startswith('min_'):
                    # Handle built-in statistics
                    if field_name == 'avg_score':
                        group_stats[field_name] = func([r.score for r in results])
                    elif field_name == 'max_score':
                        group_stats[field_name] = func([r.score for r in results])
                    elif field_name == 'min_score':
                        group_stats[field_name] = func([r.score for r in results])
                else:
                    # Custom field aggregation
                    values = [result.metadata.get(field_name) for result in results]
                    # Filter out None values for numeric operations
                    valid_values = [v for v in values if v is not None]
                    group_stats[field_name] = func(valid_values)
            except Exception as e:
                # Handle cases where aggregation might fail (empty lists, type errors)
                group_stats[field_name] = None

        result_dict[group_value] = group_stats

    return result_dict
